        s += 1
    else:
        if cc[x,y+1,z] == 0:
            s += 1
    # z negative
    if z == 0:
        s += 1
    else: 
        if cc[x,y,z-1] == 0:
            s += 1
    # z positive
    if z == 21:
        s += 1
